function resizeHomeCover(file){
  return new Promise((resolve,reject)=>{
    const reader=new FileReader();
    reader.onerror=()=>reject(new Error("read"));
    reader.onload=()=>{
      const img=new Image();
      img.onerror=()=>reject(new Error("image"));
      img.onload=()=>{
        const size=600;
        const canvas=document.createElement("canvas");
        canvas.width=size;canvas.height=size;
        const ctx=canvas.getContext("2d");
        ctx.fillStyle="rgba(0,0,0,0)";ctx.fillRect(0,0,size,size);
        const scale=Math.min((size-32)/img.width,(size-32)/img.height);
        const w=img.width*scale,h=img.height*scale;
        ctx.drawImage(img,(size-w)/2,(size-h)/2,w,h);
        resolve(canvas.toDataURL("image/webp",.82));
      };
      img.src=reader.result;
    };
    reader.readAsDataURL(file);
  });
}

function bindTileEditor(id){
  document.querySelector("#globalTileEditor")?.remove();
  const host=document.createElement("div");
  host.id="globalTileEditor";
  host.innerHTML=tileEditor(id);
  document.body.appendChild(host);
  document.body.classList.add("tile-editor-open");

  const backdrop=host.querySelector(".tile-editor-backdrop");
  const close=()=>{
    host.remove();
    document.body.classList.remove("tile-editor-open");
  };
  backdrop?.addEventListener("click",e=>{if(e.target.matches("[data-close-tile-editor]"))close()});
  host.querySelector("#tilePickImage")?.addEventListener("click",()=>host.querySelector("#tileImageInput")?.click());
  host.querySelector("#tileImageInput")?.addEventListener("change",async e=>{
    const file=e.target.files?.[0]; if(!file) return;
    try{data.homeImages=data.homeImages||{};data.homeImages[id]=await resizeHomeCover(file);saveData();close();bindTileEditor(id);toast("Cover image added ✨")}catch{toast("That image could not be added")}
  });
  host.querySelector("#tileRemoveImage")?.addEventListener("click",()=>{delete data.homeImages[id];saveData();close();bindTileEditor(id);toast("Cover image removed")});
  const moveTile=step=>{
    const i=data.homeLayout.findIndex(x=>x.id===id);const j=i+step;
    if(i<0||j<0||j>=data.homeLayout.length){toast(step<0?"This tile is already first":"This tile is already last");return;}
    [data.homeLayout[i],data.homeLayout[j]]=[data.homeLayout[j],data.homeLayout[i]];
    saveData();close();bindTileEditor(id);toast(step<0?"Tile moved earlier":"Tile moved later");
  };
  host.querySelector("#tileMoveEarlier")?.addEventListener("click",()=>moveTile(-1));
  host.querySelector("#tileMoveLater")?.addEventListener("click",()=>moveTile(1));
  host.querySelector("#tileHide")?.addEventListener("click",()=>{
    data.homeLayout=data.homeLayout.filter(x=>x.id!==id);data.homeHidden=data.homeHidden||[];if(!data.homeHidden.includes(id))data.homeHidden.push(id);saveData();close();render();
  });
  host.querySelector("#tileSave")?.addEventListener("click",()=>{
    const name=host.querySelector("#tileEditorName").value.trim().slice(0,40);
    const icon=host.querySelector("#tileEditorIcon").value.trim().slice(0,12);
    const size=host.querySelector("#tileEditorSize").value;
    data.homeTileNames=data.homeTileNames||{};data.homeIcons=data.homeIcons||{};
    if(name)data.homeTileNames[id]=name;else delete data.homeTileNames[id];
    if(icon)data.homeIcons[id]=icon;else delete data.homeIcons[id];
    const item=data.homeLayout.find(x=>x.id===id);if(item)item.size=size;
    saveData();close();render();toast("Home tile updated ✨");
  });
}

function bindHomeTileDragging(){
  const grid=document.querySelector(".home-layout.editing");
  if(!grid) return;
  let source=null,ghost=null,holdTimer=null,pointerId=null;
  let startX=0,startY=0,offsetX=0,offsetY=0,active=false,lastTarget=null,lockedScrollY=0;

  const clearHold=()=>{if(holdTimer){clearTimeout(holdTimer);holdTimer=null}};
  const clearTarget=()=>{lastTarget?.classList.remove("drag-target");lastTarget=null};
  const cleanup=({save=false}={})=>{
    clearHold();clearTarget();
    document.body.classList.remove("home-tile-dragging");
    if(document.body.classList.contains("home-tile-scroll-locked")){
      document.body.classList.remove("home-tile-scroll-locked");
      document.body.style.top="";
      window.scrollTo(0,lockedScrollY);
    }
    source?.classList.remove("drag-ready","drag-source");
    ghost?.remove();ghost=null;
    if(save&&source){
      const ids=[...grid.querySelectorAll(".home-tile-wrap[data-home-id]")].map(el=>el.dataset.homeId);
      const byId=new Map(data.homeLayout.map(item=>[item.id,item]));
      data.homeLayout=ids.map(id=>byId.get(id)).filter(Boolean);
      saveData();
      toast("Home tiles reordered ✨");
    }
    source=null;pointerId=null;active=false;
  };
  const moveGhost=(x,y)=>{
    if(!ghost)return;
    ghost.style.setProperty("--drag-x",`${x-offsetX}px`);
    ghost.style.setProperty("--drag-y",`${y-offsetY}px`);
  };
  const beginDrag=(event)=>{
    if(!source)return;
    active=true;
    source.classList.remove("drag-ready");
    source.classList.add("drag-source");
    lockedScrollY=window.scrollY;
    document.body.style.top=`-${lockedScrollY}px`;
    document.body.classList.add("home-tile-dragging","home-tile-scroll-locked");
    const rect=source.getBoundingClientRect();
    offsetX=event.clientX-rect.left;offsetY=event.clientY-rect.top;
    ghost=source.cloneNode(true);
    ghost.classList.add("home-tile-drag-ghost");
    ghost.classList.remove("drag-source","drag-ready","drag-target");
    ghost.style.width=`${rect.width}px`;ghost.style.height=`${rect.height}px`;
    document.body.appendChild(ghost);
    moveGhost(event.clientX,event.clientY);
    try{source.setPointerCapture(pointerId)}catch{}
    if(navigator.vibrate) navigator.vibrate(18);
  };

  grid.querySelectorAll(".home-tile-wrap[data-home-id]").forEach(tile=>{
    tile.addEventListener("pointerdown",event=>{
      if(event.pointerType==="mouse"&&event.button!==0)return;
      if(event.target.closest("button,input,select,label,a"))return;
      cleanup();
      source=tile;pointerId=event.pointerId;startX=event.clientX;startY=event.clientY;
      tile.classList.add("drag-ready");
      holdTimer=setTimeout(()=>beginDrag(event),180);
    });
  });

  grid.addEventListener("pointermove",event=>{
    if(!source||event.pointerId!==pointerId)return;
    const distance=Math.hypot(event.clientX-startX,event.clientY-startY);
    if(!active){
      if(distance>10){clearHold();source.classList.remove("drag-ready");source=null;pointerId=null}
      return;
    }
    event.preventDefault();
    moveGhost(event.clientX,event.clientY);
    ghost.style.visibility="hidden";
    const target=document.elementFromPoint(event.clientX,event.clientY)?.closest(".home-tile-wrap[data-home-id]");
    ghost.style.visibility="";
    if(!target||target===source||!grid.contains(target)){clearTarget();return}
    if(lastTarget!==target){clearTarget();lastTarget=target;target.classList.add("drag-target")}
    const rect=target.getBoundingClientRect();
    const before=event.clientY<rect.top+rect.height/2 || (Math.abs(event.clientY-(rect.top+rect.height/2))<rect.height*.28&&event.clientX<rect.left+rect.width/2);
    if(before) grid.insertBefore(source,target); else grid.insertBefore(source,target.nextSibling);
  },{passive:false});
  const finish=event=>{if(!source||event.pointerId!==pointerId)return;cleanup({save:active})};
  grid.addEventListener("pointerup",finish);
  grid.addEventListener("pointercancel",()=>cleanup());
  window.addEventListener("blur",()=>cleanup());
}

function bindHome(){
  const menuToggle=document.querySelector("#homeMenuToggle");
  const menu=document.querySelector("#homeMenu");
  const closeMenu=()=>{if(!menu||!menuToggle)return;menu.hidden=true;menuToggle.setAttribute("aria-expanded","false")};
  menuToggle?.addEventListener("click",event=>{event.stopPropagation();const opening=menu.hidden;menu.hidden=!opening;menuToggle.setAttribute("aria-expanded",String(opening))});
  document.addEventListener("click",event=>{if(!event.target.closest(".home-menu-wrap")) closeMenu()},{once:true});
  document.querySelector("#homeThemes")?.addEventListener("click",()=>{data.settingsSection="appearance";saveData();go("settings")});
  document.querySelector("#homeEditToggle")?.addEventListener("click",()=>{data.homeEditing=!data.homeEditing;saveData();render()});
  if(!data.homeEditing) return;
  bindHomeTileDragging();
  const saveRender=()=>{saveData();render()};
  document.querySelectorAll("[data-edit-home-tile]").forEach(tileButton=>tileButton.addEventListener("click",event=>{
    event.preventDefault();event.stopPropagation();bindTileEditor(tileButton.dataset.editHomeTile);
  }));
  document.querySelectorAll("[data-show-tile]").forEach(btn=>btn.addEventListener("click",()=>{
    const id=btn.dataset.showTile;data.homeHidden=data.homeHidden.filter(x=>x!==id);data.homeLayout.push({id,size:id==="treasures"?"wide":"medium"});saveRender();
  }));
}


/* ===== pages/today.js ===== */
function daysSinceDate(value){
  if(!value) return Infinity;
  const then=new Date(`${value}T12:00:00`);
  const now=new Date(`${today()}T12:00:00`);
  return Math.floor((now-then)/86400000);
}

function getTodayItems(){
  const items=[];
  const now=new Date();
  const hour=now.getHours();
  const weekday=now.toLocaleDateString("en-GB",{weekday:"long"});

  const todayValue=today();
  const shortDay=["Sun","Mon","Tue","Wed","Thu","Fri","Sat"][now.getDay()];
  (data.medications||[]).forEach(m=>{
    const active=m.active!==false && (!m.startDate||todayValue>=m.startDate) && (!m.endDate||todayValue<=m.endDate);
    const due=active && (m.scheduleType==="daily" || (m.scheduleType==="weekdays"&&(m.weekdays||[]).includes(shortDay)));
    const historyTaken=(data.medicationHistory||[]).filter(log=>log.medId===m.id&&log.date===todayValue).length;
    const legacyTaken=!data.medicationHistoryMigrated&&Boolean(data.medicationLog?.[todayValue]?.[m.id]);
    const taken=Math.max(historyTaken,legacyTaken?1:0);
    const required=Math.max(1,Number(m.dosesPerDay)||1);
    if(due&&taken<required){
      const doseNumber=taken+1;
      const period=(m.time&&/^\d{2}:\d{2}$/.test(m.time))?(Number(m.time.slice(0,2))<12?"AM":"PM"):(required===1?"AM":required===2?(doseNumber===1?"AM":"PM"):`Dose ${doseNumber}`);
      items.push({emoji:"💊",title:m.name,detail:[period,String(doseNumber),m.dose].filter(Boolean).join(" · "),route:"medication",kind:"Medication",completeType:"medication",completeId:m.id});
    }
  });

  (data.houseTasks||[]).forEach(t=>{
    if(houseTaskDue(t,todayValue)) items.push({emoji:t.id==="recycling"?"♻️":"🏡",title:t.task,detail:`${t.room} · ${t.frequency}`,route:"house",kind:"House",completeType:"house",completeId:t.id});
  });

  (data.personalTasks||[]).forEach(task=>{
    if(!task.done&&(!task.date||task.date<=today())){
      items.push({emoji:"✅",title:task.title,detail:[task.energy?`${task.energy} energy`:null,task.time?`Due ${task.time}`:null].filter(Boolean).join(" · ")||"Personal task",route:"todo",kind:"To-do",completeType:"todo",completeId:task.id});
    }
  });

  (data.plants||[]).forEach(plant=>{
    const interval=Number(plant.wateringDays)||0;
    if(interval>0 && daysSinceDate(plant.lastWatered)>=interval){
      items.push({emoji:"💧",title:`Water ${plant.name}`,detail:plant.lastWatered?`Last watered ${formatDate(plant.lastWatered)}`:"No watering logged yet",route:"plant",routeId:plant.id,kind:"Garden",completeType:"water",completeId:plant.id});
    }
  });

  const aquariumOrder=["boys-tank","girls-tank"];
  [...(data.aquariums||[])]
    .sort((a,b)=>aquariumOrder.indexOf(a.id)-aquariumOrder.indexOf(b.id))
    .forEach(tank=>{
      if(tankFeedToday(tank)) return;
      const label=tank.id==="boys-tank"?"Feed boys’ tank":tank.id==="girls-tank"?"Feed girls’ tank":`Feed ${tank.name}`;
      items.push({emoji:tank.emoji||"🐠",title:label,detail:"Tap ✓ when fed",route:"tank",routeId:tank.id,kind:"Aquariums",completeType:"aquarium-feed",completeId:tank.id});
    });

  items.push({emoji:"💜",title:data.checkins[today()]?"Review today’s check-in":"Complete today’s check-in",detail:data.checkins[today()]?"Saved for today":"Not completed yet",route:"journal",kind:"Journal"});
  return items;
}

function TodayPage(){
  const items=getTodayItems(),groups={};
  const completedHouse=(data.houseTasks||[]).filter(task=>houseCompletedToday(task));
  items.forEach(item=>{groups[item.kind]=groups[item.kind]||[];groups[item.kind].push(item)});
  return shell(`${head("Today",niceDate())}
    <section class="card"><div class="stat-grid"><div class="stat"><strong>${items.length}</strong><span>Remaining today</span></div><div class="stat"><strong>${(data.personalTasks||[]).filter(t=>!t.done).length}</strong><span>Open to-dos</span></div></div></section>
    ${Object.entries(groups).map(([group,groupItems])=>`<details class="card today-group"><summary><span><strong>${esc(group)}</strong><small>${groupItems.length} remaining</small></span><b>⌄</b></summary><div class="today-task-list">${groupItems.map(item=>`<article class="item-row today-task" data-today-item><button type="button" class="today-task-main" data-route="${item.route}" ${item.routeId?`data-route-id="${esc(item.routeId)}"`:""}><span class="today-task-icon">${item.emoji}</span><span><h3>${esc(item.title)}</h3><p>${esc(item.detail)}</p></span><span class="plant-arrow">›</span></button>${item.completeType?`<button type="button" class="check-task today-quick-done" data-today-complete="${esc(item.completeType)}" data-today-id="${esc(item.completeId)}">✓</button>`:""}</article>`).join("")}</div></details>`).join("")}
    ${completedHouse.length?`<details class="card today-completed-card"><summary>✓ Completed today · ${completedHouse.length}</summary><div class="today-completed-list">${completedHouse.map(task=>`<div class="today-completed-row"><span><strong>${esc(task.task)}</strong><small>${esc(task.room)} · ${esc(task.frequency)}</small></span><button type="button" class="mini" data-today-complete="house" data-today-id="${esc(task.id)}">Undo</button></div>`).join("")}</div></details>`:""}`,'today');
}

function bindToday(){
  const page=document.querySelector('.shell');
  if(!page)return;
  page.addEventListener('click',event=>{
    const button=event.target.closest('[data-today-complete]');
    if(!button)return;
    event.preventDefault();
    event.stopPropagation();
    const type=button.dataset.todayComplete;
    const id=String(button.dataset.todayId||'');
    let message='Marked as done ✨';

    if(type==='house'){
      const task=(data.houseTasks||[]).find(item=>String(item.id)===id);
      if(!task)return;
      const completed=!houseCompletedToday(task);
      setHouseTaskCompleted(task,completed);
      message=completed?'House job completed 🏡':'House completion removed';
    }else if(type==='todo'){
      const task=(data.personalTasks||[]).find(item=>String(item.id)===id);
      if(!task)return;
      task.done=true;
      task.completed=today();
      message='Task completed ✨';
    }else if(type==='water'){
      const plant=(data.plants||[]).find(item=>String(item.id)===id);
      if(!plant)return;
      plant.history=Array.isArray(plant.history)?plant.history:[];
      if(!plant.history.includes(today())) plant.history.push(today());
      plant.history.sort();
      plant.lastWatered=today();
      message=`${plant.name} watered 💧`;
    }else if(type==='medication'){
      const med=(data.medications||[]).find(item=>String(item.id)===id);
      if(!med)return;
      const now=new Date(),pad=n=>String(n).padStart(2,'0');
      data.medicationHistory=Array.isArray(data.medicationHistory)?data.medicationHistory:[];
      const doseDate=today();
      data.medicationHistory.push({id:`dose-${Date.now()}-${Math.random().toString(36).slice(2,7)}`,medId:med.id,date:doseDate,time:`${pad(now.getHours())}:${pad(now.getMinutes())}`,notes:'',createdAt:now.toISOString()});
      data.medicationLog=data.medicationLog&&typeof data.medicationLog==='object'?data.medicationLog:{};
      data.medicationLog[doseDate]=data.medicationLog[doseDate]&&typeof data.medicationLog[doseDate]==='object'?data.medicationLog[doseDate]:{};
      data.medicationLog[doseDate][med.id]=true;
      message=`${med.name} marked as taken 💊`;
    }else if(type==='aquarium-feed'){
      const tank=(data.aquariums||[]).find(item=>String(item.id)===id);
      if(!tank)return;
      tank.feeds=Array.isArray(tank.feeds)?tank.feeds:[];
      if(!tankFeedToday(tank)) tank.feeds.push({id:`feed-${Date.now()}-${Math.random().toString(36).slice(2,7)}`,food:"Fed from Today",createdAt:new Date().toISOString()});
      message=`${tank.name} fed 🐠`;
    }else return;

    saveData();
    const row=button.closest('[data-today-item]');
    row?.classList.add('today-item-completing');
    button.classList.add('done');
    toast(message);
    setTimeout(()=>render(),180);
  });
}


/* ===== pages/todo.js ===== */

function normalizeTodoTask(task,index=0){
  const deadline=task?.deadline||task?.date||"";
  return {
    id:String(task?.id||`todo-${Date.now()}-${index}`),
    title:String(task?.title||task?.task||"Untitled task"),
    energy:["Low","Medium","High"].includes(task?.energy)?task.energy:"Medium",
    deadline,
    date:deadline,
    time:"",
    done:task?.done===true,
    created:task?.created||today(),
    completed:task?.completed||""
  };
}

function todoEnergyIcon(energy){
  return energy==="Low"?"🟢":energy==="High"?"🔴":"🟡";
}

function TodoPage(){
  data.personalTasks=Array.isArray(data.personalTasks)
    ? data.personalTasks.map(normalizeTodoTask)
    : [];

  const openTasks=data.personalTasks.filter(task=>!task.done);
  const completed=data.personalTasks.filter(task=>task.done);

  return shell(`${head("To-do List","Tasks carry over until you complete them")}
    <section class="card">
      <h2>➕ Add a task</h2>
      <div class="form-grid" id="todoForm">
        <input class="field" id="todoTitle" placeholder="What do you want to do?" autocomplete="off">

        <div>
          <span class="field-label">Energy needed</span>
          <div class="energy-picker" id="todoEnergyPicker">
            <button type="button" class="energy-choice" data-energy-choice="Low"><span>🟢</span><b>Low</b></button>
            <button type="button" class="energy-choice active" data-energy-choice="Medium"><span>🟡</span><b>Medium</b></button>
            <button type="button" class="energy-choice" data-energy-choice="High"><span>🔴</span><b>High</b></button>
          </div>
          <input type="hidden" id="todoEnergy" value="Medium">
        </div>

        <label class="field-label">Optional deadline
          <input class="field" id="todoDeadline" type="date">
        </label>

        <button type="button" class="primary" id="addTodo">Add to list</button>
      </div>
      <p style="margin-bottom:0">Leave the date blank and it will carry over every day until completed.</p>
    </section>

    <section class="card">
      <div class="section-title">
        <div><span class="section-kicker">✨ Your list</span><h2>Open tasks</h2></div>
        <span class="todo-count">${openTasks.length}</span>
      </div>
      <div class="list-card" id="openTodoList">
        ${openTasks.length?openTasks.map(task=>`
          <article class="item-row todo-item" data-todo-id="${esc(task.id)}">
            <div>
              <h3>${esc(task.title)}</h3>
              <p>${todoEnergyIcon(task.energy)} ${esc(task.energy)} energy${task.deadline?` · Deadline ${esc(formatDate(task.deadline))}`:" · Carries over daily"}</p>
            </div>
            <div class="item-actions">
              <button type="button" class="check-task" data-todo-done="${esc(task.id)}" aria-label="Complete ${esc(task.title)}">✓</button>
              <button type="button" class="mini danger" data-todo-delete="${esc(task.id)}">Delete</button>
            </div>
          </article>`).join(""):`<p class="empty-todo">No open tasks. ✨</p>`}
      </div>
    </section>

    ${completed.length?`<details class="card completed-tasks-panel">
      <summary class="completed-tasks-summary">
        <span><span class="section-kicker">💜 Finished</span><strong>Completed tasks</strong><small>${completed.length} hidden</small></span>
        <b class="completed-chevron">⌄</b>
      </summary>
      <div class="completed-tasks-content">
        <div class="completed-actions"><button type="button" class="mini" id="clearCompleted">Clear all</button></div>
        <div class="list-card">
          ${completed.slice().reverse().map(task=>`
            <article class="item-row completed-task">
              <div>
                <h3>${esc(task.title)}</h3>
                <p>${todoEnergyIcon(task.energy)} ${esc(task.energy)} energy${task.completed?` · Completed ${esc(formatDate(task.completed))}`:""}</p>
              </div>
              <div class="item-actions">
                <button type="button" class="mini" data-todo-undo="${esc(task.id)}">Undo</button>
                <button type="button" class="mini danger" data-todo-delete="${esc(task.id)}">Delete</button>
              </div>
            </article>`).join("")}
        </div>
      </div>
    </details>`:""}
  `,"todo");
}

function bindTodo(){
  const page=document.querySelector('[data-route="todo"].active')?.closest("nav")?.previousElementSibling||document.querySelector(".shell");
  if(!page) return;

  const titleInput=page.querySelector("#todoTitle");
  const energyInput=page.querySelector("#todoEnergy");

  page.addEventListener("click",event=>{
    const energyButton=event.target.closest("[data-energy-choice]");
    if(energyButton){
      page.querySelectorAll("[data-energy-choice]").forEach(button=>button.classList.remove("active"));
      energyButton.classList.add("active");
      if(energyInput) energyInput.value=energyButton.dataset.energyChoice;
      return;
    }

    const addButton=event.target.closest("#addTodo");
    if(addButton){
      addTodoTask();
      return;
    }

    const doneButton=event.target.closest("[data-todo-done]");
    if(doneButton){
      const id=String(doneButton.dataset.todoDone);
      const task=data.personalTasks.find(item=>String(item.id)===id);
      if(task){
        task.done=true;
        task.completed=today();
        saveData();
        toast("Task completed ✨");
        render();
      }
      return;
    }

    const undoButton=event.target.closest("[data-todo-undo]");
    if(undoButton){
      const id=String(undoButton.dataset.todoUndo);
      const task=data.personalTasks.find(item=>String(item.id)===id);
      if(task){
        task.done=false;
        task.completed="";
        saveData();
        toast("Task moved back to your list");
        render();
      }
      return;
    }

    const deleteButton=event.target.closest("[data-todo-delete]");
    if(deleteButton){
      const id=String(deleteButton.dataset.todoDelete);
      data.personalTasks=data.personalTasks.filter(item=>String(item.id)!==id);
      saveData();
      toast("Task deleted");
      render();
      return;
    }

    if(event.target.closest("#clearCompleted")){
      data.personalTasks=data.personalTasks.filter(task=>!task.done);
      saveData();
      toast("Completed tasks cleared");
      render();
    }
  });

  titleInput?.addEventListener("keydown",event=>{
    if(event.key==="Enter"){
      event.preventDefault();
      addTodoTask();
    }
  });

  function addTodoTask(){
    const title=(titleInput?.value||"").trim();
    if(!title){
      toast("Add a task first");
      titleInput?.focus();
      return;
    }

    const deadline=page.querySelector("#todoDeadline")?.value||"";
    data.personalTasks=Array.isArray(data.personalTasks)?data.personalTasks:[];
    data.personalTasks.push({
      id:`todo-${Date.now()}-${Math.random().toString(36).slice(2,7)}`,
      title,
      energy:energyInput?.value||"Medium",
      deadline,
      date:deadline,
      time:"",
      done:false,
      created:today(),
      completed:""
    });

    saveData();
    toast("Task added ✅");
    render();
  }
}


/* ===== pages/shopping.js ===== */
const SHOPPING_CATEGORIES=[
  {id:"fridge",name:"Fridge",iconKey:"shoppingFridge",fallback:"❄️",hint:"Fresh food, dairy and chilled items"},
  {id:"freezer",name:"Freezer",iconKey:"shoppingFreezer",fallback:"🧊",hint:"Frozen food and ice"},
  {id:"pantry",name:"Pantry",iconKey:"shoppingPantry",fallback:"🥫",hint:"Cupboard food, drinks and snacks"},
  {id:"cleaning",name:"Cleaning Supplies",iconKey:"shoppingCleaning",fallback:"🧽",hint:"Laundry and household cleaning"},
  {id:"toiletries",name:"Toiletries",iconKey:"shoppingToiletries",fallback:"🧴",hint:"Bathroom and personal care"}
];

function normaliseShoppingCategory(value=""){
  const text=String(value).toLowerCase();
  if(text.includes("freezer")||text.includes("frozen")) return "freezer";
  if(text.includes("clean")||text.includes("household")||text.includes("laundry")) return "cleaning";
  if(text.includes("toilet")||text.includes("bathroom")||text.includes("personal")) return "toiletries";
  if(text.includes("fridge")||text.includes("chill")||text.includes("dairy")||text.includes("fruit")||text.includes("veg")) return "fridge";
  return "pantry";
}

function ensureShoppingData(){
  data.shoppingItems=Array.isArray(data.shoppingItems)?data.shoppingItems:[];
  data.shoppingItems=data.shoppingItems.map(item=>({...item,category:normaliseShoppingCategory(item.category)}));
  data.shoppingView=data.shoppingView||{};
  data.shoppingView.category=SHOPPING_CATEGORIES.some(c=>c.id===data.shoppingView.category)?data.shoppingView.category:"all";
}

function shoppingCategory(id){return SHOPPING_CATEGORIES.find(c=>c.id===id)||SHOPPING_CATEGORIES[2]}

function shoppingItemRow(item){
  const category=shoppingCategory(item.category);
  return `<article class="shopping-item ${item.done?"shopping-item-done":""}">
    <button type="button" class="shopping-check ${item.done?"done":""}" data-shopping-toggle="${esc(item.id)}" aria-label="${item.done?"Put back on list":"Mark as bought"}">${item.done?"✓":""}</button>
    <div class="shopping-item-copy"><strong>${esc(item.name)}</strong><small>${item.quantity?`${esc(item.quantity)} · `:""}${esc(category.name)}</small></div>
    <button type="button" class="shopping-delete" data-shopping-delete="${esc(item.id)}" aria-label="Delete ${esc(item.name)}">×</button>
  </article>`;
}

function ShoppingPage(){
  ensureShoppingData();
  const active=data.shoppingView.category||"all";
  const items=data.shoppingItems||[];
  const needed=items.filter(item=>!item.done);
  const filtered=active==="all"?needed:needed.filter(item=>item.category===active);
  const bought=items.filter(item=>item.done);
  const categoryTiles=SHOPPING_CATEGORIES.map(category=>{
    const count=needed.filter(item=>item.category===category.id).length;
    return `<button type="button" class="shopping-category-tile ${active===category.id?"active":""}" data-shopping-category="${category.id}">
      <span class="shopping-category-art">${moduleVisual(category.iconKey,category.fallback,"module-tile-image")}</span>
      <span class="shopping-category-copy"><strong>${category.name}</strong><small>${count?`${count} item${count===1?"":"s"} to buy`:category.hint}</small></span>
      <b>${count}</b>
    </button>`;
  }).join("");

  return shell(`${head("Shopping","Add it at home, tick it off in the shop")}
    <section class="card shopping-overview-card">
      <div><span class="section-kicker">Shopping list</span><h2>${needed.length?`${needed.length} item${needed.length===1?"":"s"} still needed`:"Your list is clear"}</h2><p>${needed.length?"Choose a category or view the full list below.":"Add something whenever you notice you are running low."}</p></div>
      <span class="shopping-overview-count">${needed.length}</span>
    </section>

    <section class="shopping-category-grid">${categoryTiles}</section>

    <section class="card shopping-quick-card">
      <div class="shopping-add-row">
        <input class="field" id="shoppingName" type="text" maxlength="80" placeholder="Add an item…" autocomplete="off">
        <button type="button" class="primary shopping-add-button" id="addShoppingItem">Add</button>
      </div>
      <div class="shopping-options">
        <input class="field" id="shoppingQuantity" type="text" maxlength="30" placeholder="Quantity (optional)">
        <select class="field" id="shoppingCategory">${SHOPPING_CATEGORIES.map(c=>`<option value="${c.id}" ${active===c.id?"selected":""}>${c.name}</option>`).join("")}</select>
      </div>
    </section>

    <section class="shopping-list-section">
      <div class="section-title-row">
        <h2>${active==="all"?"Everything to buy":shoppingCategory(active).name}</h2>
        ${active!=="all"?`<button type="button" class="small-btn" data-shopping-category="all">View all</button>`:""}
      </div>
      <div class="shopping-list">${filtered.length?filtered.map(shoppingItemRow).join(""):`<div class="card empty shopping-empty"><span>✓</span><p>${active==="all"?"Nothing left to buy.":`Nothing needed for ${shoppingCategory(active).name.toLowerCase()}.`}</p></div>`}</div>
    </section>

    ${bought.length?`<details class="card shopping-bought-details"><summary>Bought today (${bought.length})</summary><div class="shopping-list">${bought.map(shoppingItemRow).join("")}</div><button type="button" class="small-btn danger shopping-clear" id="clearBoughtShopping">Clear bought</button></details>`:""}
  `,"shopping");
}

function bindShopping(){
  ensureShoppingData();
  const page=document.querySelector("#app");
  const nameInput=page?.querySelector("#shoppingName");
  const addItem=()=>{
    const name=(nameInput?.value||"").trim();
    if(!name){toast("Add an item first");nameInput?.focus();return;}
    const quantity=(page.querySelector("#shoppingQuantity")?.value||"").trim();
    const category=page.querySelector("#shoppingCategory")?.value||"pantry";
    data.shoppingItems.unshift({id:`shop-${Date.now()}-${Math.random().toString(36).slice(2,7)}`,name,quantity,category,done:false,createdAt:new Date().toISOString(),completedAt:""});
    saveData();render();requestAnimationFrame(()=>document.querySelector("#shoppingName")?.focus());
  };
  page?.querySelector("#addShoppingItem")?.addEventListener("click",addItem);
  nameInput?.addEventListener("keydown",event=>{if(event.key==="Enter"){event.preventDefault();addItem();}});
  page?.addEventListener("click",event=>{
    const category=event.target.closest("[data-shopping-category]");
    if(category){data.shoppingView.category=category.dataset.shoppingCategory;saveData();render();return;}
    const toggle=event.target.closest("[data-shopping-toggle]");
    if(toggle){const item=data.shoppingItems.find(x=>String(x.id)===String(toggle.dataset.shoppingToggle));if(item){item.done=!item.done;item.completedAt=item.done?new Date().toISOString():"";saveData();render();}return;}
    const remove=event.target.closest("[data-shopping-delete]");
    if(remove){data.shoppingItems=data.shoppingItems.filter(x=>String(x.id)!==String(remove.dataset.shoppingDelete));saveData();render();return;}
    if(event.target.closest("#clearBoughtShopping")){data.shoppingItems=data.shoppingItems.filter(item=>!item.done);saveData();render();toast("Bought items cleared");}
  });
}


